    'gr': 'Grams',
    'g': 'Grams',
    'gram': 'Grams',
    'grams': 'Grams',
    'in': 'Inches',
    'inch': 'Inches',
    'inches': 'Inches',
    'cm': 'Centimeters',
    'centimeter': 'Centimeters',
    'centimeters': 'Centimeters',
    'mm': 'Millimeters',
    'millimeter': 'Millimeters',
