const HIGH_CONFIDENCE_KEYWORDS = [
  'item_sku', 'external_product_id', 'feed_product_type', 'item_name', 
  'brand_name', 'standard_price', 'main_image_url', 'product_description',
  'bullet_point1', 'quantity', 'update_delete', 'product_id_type'
